'use client'

import {
  cn,
  DismissableLayer,
  FocusScope,
  Portal,
  Presence,
  useControllableSignal,
  useRovingFocus,
  useSignals,
} from '@cascivo/core'
import { builtin, t } from '@cascivo/i18n'
import { useId } from 'react'
import type { ReactNode } from 'react'
import styles from './action-sheet.module.css'

export interface ActionSheetAction {
  label: ReactNode
  onSelect: () => void
  /** Render in the destructive (danger) style. */
  destructive?: boolean
  disabled?: boolean
}

export interface ActionSheetProps {
  /** Controlled open state. */
  open?: boolean
  /** Initial open state for uncontrolled use. */
  defaultOpen?: boolean
  /** Called whenever the open state should change (selection, cancel, Escape, outside press). */
  onOpenChange?: (open: boolean) => void
  /** The choices presented, top to bottom. */
  actions: ActionSheetAction[]
  /** Optional heading shown above the actions; also labels the menu. */
  title?: ReactNode
  /** Optional supporting message under the title. */
  description?: ReactNode
  /** Show the separate Cancel button. Default true. */
  showCancel?: boolean
  labels?: { cancel?: string; label?: string }
  className?: string
}

/**
 * Bottom-rising sheet of discrete actions (iOS action-sheet pattern). Renders a
 * role="menu" of menuitems with vertical roving focus (Arrow keys, Home/End, wraps);
 * Escape and outside press dismiss it, and a separate Cancel button gives an explicit
 * non-destructive exit. Body scroll is not locked — the sheet is transient. Reuses the
 * overlay primitives and CSS-only slide; no animation library.
 */
export function ActionSheet({
  open,
  defaultOpen,
  onOpenChange,
  actions,
  title,
  description,
  showCancel = true,
  labels,
  className,
}: ActionSheetProps) {
  useSignals()
  const [isOpen, setOpen] = useControllableSignal<boolean>({
    value: open,
    defaultValue: defaultOpen ?? false,
    onChange: onOpenChange,
  })

  const roving = useRovingFocus({ orientation: 'vertical', loop: true })

  const titleId = useId()
  const descId = useId()
  const cancelLabel = labels?.cancel ?? t(builtin.actionSheet.cancel)
  const menuLabel = labels?.label ?? t(builtin.actionSheet.label)

  const select = (action: ActionSheetAction): void => {
    if (action.disabled) return
    action.onSelect()
    setOpen(false)
  }

  // Cancel is the last roving item so Arrow keys reach it.
  const cancelIndex = actions.length

  return (
    <Portal>
      <Presence present={isOpen}>
        <div className={styles['overlay']}>
          <DismissableLayer onDismiss={() => setOpen(false)}>
            <FocusScope trapped restoreFocus autoFocus>
              <div
                role="menu"
                aria-label={title ? undefined : menuLabel}
                aria-labelledby={title ? titleId : undefined}
                aria-describedby={description ? descId : undefined}
                className={cn(styles['sheet'], className)}
              >
                <div className={styles['group']}>
                  {(title || description) && (
                    <div className={styles['heading']} role="presentation">
                      {title && (
                        <p id={titleId} className={styles['title']}>
                          {title}
                        </p>
                      )}
                      {description && (
                        <p id={descId} className={styles['description']}>
                          {description}
                        </p>
                      )}
                    </div>
                  )}
                  {actions.map((action, index) => {
                    const itemProps = roving.getItemProps(index)
                    return (
                      <button
                        key={index}
                        ref={itemProps.ref as React.Ref<HTMLButtonElement>}
                        type="button"
                        role="menuitem"
                        tabIndex={itemProps.tabIndex}
                        aria-disabled={action.disabled || undefined}
                        data-destructive={action.destructive ? '' : undefined}
                        className={styles['item']}
                        onKeyDown={itemProps.onKeyDown}
                        onFocus={itemProps.onFocus}
                        onClick={() => select(action)}
                      >
                        {action.label}
                      </button>
                    )
                  })}
                </div>
                {showCancel && (
                  <div className={styles['group']}>
                    {(() => {
                      const itemProps = roving.getItemProps(cancelIndex)
                      return (
                        <button
                          ref={itemProps.ref as React.Ref<HTMLButtonElement>}
                          type="button"
                          role="menuitem"
                          tabIndex={itemProps.tabIndex}
                          className={cn(styles['item'], styles['cancel'])}
                          onKeyDown={itemProps.onKeyDown}
                          onFocus={itemProps.onFocus}
                          onClick={() => setOpen(false)}
                        >
                          {cancelLabel}
                        </button>
                      )
                    })()}
                  </div>
                )}
              </div>
            </FocusScope>
          </DismissableLayer>
        </div>
      </Presence>
    </Portal>
  )
}

@layer cascivo.component {
  .overlay {
    position: fixed;
    inset: 0;
    z-index: var(--cascivo-z-overlay, 50);
    display: flex;
    flex-direction: column;
    justify-content: flex-end;
    align-items: center;
    padding: var(--cascivo-space-3);
    padding-block-end: calc(var(--cascivo-space-3) + env(safe-area-inset-bottom, 0px));
    background-color: rgb(0 0 0 / 0.4);
    opacity: 1;
    transition: opacity var(--cascivo-motion-enter);

    &[data-state='closed'] {
      opacity: 0;
      transition: opacity var(--cascivo-motion-exit);
    }

    @starting-style {
      &[data-state='open'] {
        opacity: 0;
      }
    }
  }

  .sheet {
    display: flex;
    flex-direction: column;
    gap: var(--cascivo-space-2);
    inline-size: 100%;
    max-inline-size: 32rem;
    translate: 0 0;
    transition: translate var(--cascivo-motion-enter);

    .overlay[data-state='closed'] & {
      translate: 0 100%;
      transition: translate var(--cascivo-motion-exit);
    }
  }

  /* Slide up from off-screen on first mount. */
  @starting-style {
    .overlay[data-state='open'] .sheet {
      translate: 0 100%;
    }
  }

  .group {
    display: flex;
    flex-direction: column;
    background: var(--cascivo-color-surface);
    border: 1px solid var(--cascivo-color-border);
    border-radius: var(--cascivo-radius-overlay);
    box-shadow: var(--cascivo-shadow-overlay);
    overflow: hidden;
  }

  .heading {
    padding: var(--cascivo-space-4) var(--cascivo-space-6);
    text-align: center;
    border-block-end: 1px solid var(--cascivo-color-border);
  }

  .title {
    margin: 0;
    font-size: var(--cascivo-text-sm);
    font-weight: var(--cascivo-font-semibold);
    color: var(--cascivo-color-text);
  }

  .description {
    margin: var(--cascivo-space-1) 0 0;
    font-size: var(--cascivo-text-sm);
    color: var(--cascivo-color-text-subtle);
  }

  .item {
    display: flex;
    align-items: center;
    justify-content: center;
    inline-size: 100%;
    min-block-size: 3rem; /* 48px — already past the 44px coarse touch target */
    padding: var(--cascivo-space-3) var(--cascivo-space-6);
    font-size: var(--cascivo-text-base);
    color: var(--cascivo-color-accent);
    background: transparent;
    border: none;
    cursor: pointer;
    transition: background-color var(--cascivo-duration-150) var(--cascivo-ease-out);

    & + .item {
      border-block-start: 1px solid var(--cascivo-color-border);
    }

    &:hover {
      background-color: var(--cascivo-color-bg-subtle);
    }

    &:focus-visible {
      outline: none;
      box-shadow: var(--cascivo-focus-ring);
      /* Keep the ring above sibling borders. */
      position: relative;
      z-index: 1;
    }

    &[aria-disabled='true'] {
      color: var(--cascivo-color-text-muted);
      cursor: not-allowed;
    }

    &[data-destructive] {
      color: var(--cascivo-color-destructive);
    }
  }

  .cancel {
    font-weight: var(--cascivo-font-semibold);
    color: var(--cascivo-color-text);
  }

  @media (prefers-reduced-motion: reduce) {
    .sheet {
      transition: none;
    }
  }
}
